@@ -1722,0 +1722,11 @@
+  void spill_copy_register_to_register(FloatRegister dst, FloatRegister src,
+                                       bool use_movprfx, bool use_sve = true,
+                                       SIMD_Arrangement T = T16B) {
+    if (use_movprfx) {
+      sve_movprfx(dst, src);
+    } else if (use_sve) {
+      sve_orr(dst, src, src);
+    } else {
+      mov(dst, T, src);
+    }
+  }
